#!/usr/bin/env node
// Generate migrations/APPLY_008_TO_LATEST.sql by concatenating the
// numbered migration files. Replaces the hand-maintained bundle that
// drifted from the individual files (D14 in the 2026-04-24 ultrareview).
//
// Run with:   node scripts/build-migration-bundle.mjs
// Or via:     npm run build:migrations

import { readdirSync, readFileSync, writeFileSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const here = dirname(fileURLToPath(import.meta.url));
const migrationsDir = join(here, "..", "migrations");

// Match 008 onwards — 001-007 predate the "bundled re-apply" story and
// shipped before tables existed, so they're not safe to re-run as a
// bundle against a live DB.
const NUMBER_RE = /^0*(\d+)-.*\.sql$/;
const BUNDLE_START = 8;

const files = readdirSync(migrationsDir)
  .filter((f) => NUMBER_RE.test(f))
  .map((f) => ({ name: f, num: Number(f.match(NUMBER_RE)[1]) }))
  .filter((f) => f.num >= BUNDLE_START)
  .sort((a, b) => a.num - b.num);

if (files.length === 0) {
  console.error("No numbered migrations found >=", BUNDLE_START);
  process.exit(1);
}

const header = `-- AUTO-GENERATED by scripts/build-migration-bundle.mjs
-- Do not edit this file by hand — it will be overwritten on the next
-- run. Edit the individual numbered files in migrations/ instead and
-- regenerate with: npm run build:migrations
--
-- Bundle of migrations ${files[0].num} through ${files[files.length - 1].num},
-- concatenated for one-shot paste into the Supabase SQL editor.
--
-- Every source migration is expected to be idempotent / resilient-to-
-- re-apply. If one isn't, fix the source file and regenerate.

`;

const body = files
  .map((f) => {
    const content = readFileSync(join(migrationsDir, f.name), "utf8");
    return `-- ──────────────────────────────────────────────────────────────────\n-- ${f.name}\n-- ──────────────────────────────────────────────────────────────────\n${content.trim()}\n`;
  })
  .join("\n");

const outPath = join(migrationsDir, "APPLY_008_TO_LATEST.sql");
writeFileSync(outPath, header + body);

console.log(`Wrote ${outPath}`);
console.log(`Bundled ${files.length} migrations: ${files.map((f) => f.num).join(", ")}`);
